content.text:
data "azurerm_client_config" "current" {}

# Reference the root management group (cannot be created — only referenced)
data "azurerm_management_group" "root" {
  name = data.azurerm_client_config.current.tenant_id
}

# Create CAF landing zone top-level groups
resource "azurerm_management_group" "platform" {
  display_name               = "Platform"
  parent_management_group_id = data.azurerm_management_group.root.id
}

resource "azurerm_management_group" "corp" {
  display_name               = "Corp"
  parent_management_group_id = data.azurerm_management_group.root.id
}

resource "azurerm_management_group" "sandbox" {
  display_name               = "Sandbox"
  parent_management_group_id = data.azurerm_management_group.root.id
}

# Assign subscription to a management group
resource "azurerm_management_group_subscription_association" "sandbox_sub" {
  management_group_id = azurerm_management_group.sandbox.id
  subscription_id     = "/subscriptions/${var.sandbox_subscription_id}"
}

# Apply a root-level policy to require the environment tag
resource "azurerm_policy_assignment" "require_env_tag" {
  name                 = "require-env-tag"
  scope                = data.azurerm_management_group.root.id
  policy_definition_id = "/providers/Microsoft.Authorization/policyDefinitions/..."
  parameters = jsonencode({
    tagName = { value = "environment" }
  })
}

targetScope = 'tenant'

param tenantId string = tenant().tenantId
param sandboxSubscriptionId string

// Reference the root management group by tenant ID
resource rootMg 'Microsoft.Management/managementGroups@2021-04-01' existing = {
  name: tenantId
  scope: tenant()
}

// Create CAF top-level groups
resource platformMg 'Microsoft.Management/managementGroups@2021-04-01' = {
  name: 'mg-platform'
  scope: tenant()
  properties: {
    displayName: 'Platform'
    details: {
      parent: {
        id: rootMg.id
      }
    }
  }
}

resource sandboxMg 'Microsoft.Management/managementGroups@2021-04-01' = {
  name: 'mg-sandbox'
  scope: tenant()
  properties: {
    displayName: 'Sandbox'
    details: {
      parent: { id: rootMg.id }
    }
  }
}

// Move sandbox subscription into the Sandbox MG
resource sandboxSubAssociation 'Microsoft.Management/managementGroups/subscriptions@2021-04-01' = {
  parent: sandboxMg
  name: sandboxSubscriptionId
}

// Assign a built-in policy at root: require 'environment' tag on all resources
resource requireTagPolicy 'Microsoft.Authorization/policyAssignments@2022-06-01' = {
  name: 'require-env-tag'
  scope: rootMg
  properties: {
    displayName: 'Require environment tag on all resources'
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/96670d01-0a4d-4649-9c89-2d3abc0a5025'
    parameters: {
      tagName: { value: 'environment' }
    }
  }
}
